CREATE OR REPLACE FUNCTION public.calculate_asset_business_total_area(p_asset_size numeric, p_area_from_distribution numeric, p_main_asset_type text)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_is_business BOOLEAN := false;
BEGIN
  IF p_main_asset_type IS NOT NULL THEN
    SELECT EXISTS (
      SELECT 1
      FROM asset_types at
      WHERE at.name = p_main_asset_type
        AND COALESCE(at.active, false) = true
        AND at.business_residence = 'עסקים'
    ) INTO v_is_business;
  END IF;

  IF v_is_business THEN
    RETURN COALESCE(p_asset_size, 0) + COALESCE(p_area_from_distribution, 0);
  ELSE
    RETURN 0;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.extract_boolean_from_jsonb(p_value jsonb, p_default boolean DEFAULT false)
 RETURNS boolean
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_text TEXT;
BEGIN
  IF p_value IS NULL OR p_value = 'null'::jsonb THEN
    RETURN p_default;
  END IF;

  IF jsonb_typeof(p_value) = 'boolean' THEN
    RETURN (p_value)::text::boolean;
  END IF;

  IF jsonb_typeof(p_value) = 'string' THEN
    v_text := TRIM(BOTH '"' FROM (p_value)::text);
    RETURN CASE
      WHEN v_text = 'כן' OR LOWER(v_text) IN ('yes', 'true', '1', 't') THEN true
      WHEN v_text = 'לא' OR LOWER(v_text) IN ('no', 'false', '0', 'f', '') THEN false
      ELSE p_default
    END;
  END IF;

  RETURN p_default;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_or_create_user_from_auth()
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id bigint;
  v_auth_user_id text;
BEGIN
  -- Try to get current user from auth context (Supabase)
  v_auth_user_id := current_setting('request.jwt.claim.sub', true);

  IF v_auth_user_id IS NOT NULL THEN
    -- First try to find existing user
    SELECT user_id INTO v_user_id
    FROM users
    WHERE auth_user_id = v_auth_user_id;

    -- Only insert if not found (no UPDATE to avoid recursion)
    IF v_user_id IS NULL THEN
      BEGIN
        INSERT INTO users (auth_user_id, user_name, user_email)
        VALUES (v_auth_user_id, v_auth_user_id, NULL)
        ON CONFLICT (auth_user_id) DO NOTHING
        RETURNING user_id INTO v_user_id;

        -- If ON CONFLICT happened, fetch the existing user_id
        IF v_user_id IS NULL THEN
          SELECT user_id INTO v_user_id
          FROM users
          WHERE auth_user_id = v_auth_user_id;
        END IF;
      EXCEPTION
        WHEN OTHERS THEN
          -- If insert fails, try to get existing user one more time
          SELECT user_id INTO v_user_id
          FROM users
          WHERE auth_user_id = v_auth_user_id;
      END;
    END IF;
  END IF;

  -- If still no user, use default
  IF v_user_id IS NULL THEN
    SELECT user_id INTO v_user_id
    FROM users
    WHERE user_name = 'default' AND auth_user_id IS NULL
    LIMIT 1;
  END IF;

  RETURN v_user_id;
END;
$function$

